func FileDescriptorSet() *descriptor.FileDescriptorSet {
	// We just need ONE of the service names to look up the FileDescriptorSet.
	ret, err := discovery.GetDescriptorSet("tokenserver.minter.TokenMinter")
	if err != nil {
		panic(err)
	}
	return ret
}
